--- (AIR) Refueling from the nearest tanker. No parameters.
-- @param #CONTROLLABLE self
-- @return DCS#Task The DCS task structure.
function CONTROLLABLE:TaskRefueling()
  self:F2( { self.ControllableName } )

--  Refueling = {
--    id = 'Refueling',
--    params = {}
--  }

  local DCSTask
  DCSTask = { id = 'Refueling',
    params = {
    },
  },

